'use client';
import { useState, useEffect, useCallback } from "react";
import { Sidebar } from "../components/Sidebar";
import { Topbar } from "../components/Topbar";
import { cn } from "@/src/shared/utils";
import { Store, ListTree, Settings as SettingsIcon, Plus, Trash2, Save, Loader2 } from "lucide-react";

type ConfigTab = 'Datos del Negocio' | 'Categorías' | 'Ajustes Generales';

// ─── Page ─────────────────────────────────────────────────────────────────────

export default function ConfiguracionPage() {
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [activeTab, setActiveTab] = useState<ConfigTab>('Datos del Negocio');

    const tabs: { id: ConfigTab; icon: any }[] = [
        { id: 'Datos del Negocio', icon: Store },
        { id: 'Categorías', icon: ListTree },
        { id: 'Ajustes Generales', icon: SettingsIcon },
    ];

    return (
        <div className="min-h-screen bg-slate-50 flex">
            <Sidebar isCollapsed={isCollapsed} setIsCollapsed={setIsCollapsed} />

            <div className={cn("flex-1 transition-all duration-300", isCollapsed ? "ml-20" : "ml-64")}>
                <Topbar />

                <main className="p-8 max-w-7xl mx-auto pb-20">
                    <div className="flex items-center justify-end mb-8">
                        {/* El título ahora está en la Topbar */}
                    </div>

                    <div className="flex flex-col lg:flex-row gap-6">
                        {/* Sidebar Menu */}
                        <div className="w-full lg:w-64 shrink-0">
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-4">
                                <h2 className="text-sm font-bold text-slate-800 mb-4 px-2">Configuración</h2>
                                <nav className="flex flex-col gap-1">
                                    {tabs.map(t => (
                                        <button key={t.id} onClick={() => setActiveTab(t.id)}
                                            className={cn("flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-semibold transition-all w-full text-left whitespace-nowrap",
                                                activeTab === t.id ? "bg-[#40C4AA] text-white shadow-md shadow-teal-200" : "text-slate-500 hover:bg-slate-50"
                                            )}>
                                            <t.icon className={cn("w-5 h-5", activeTab === t.id ? "text-white" : "text-slate-400")} />
                                            {t.id}
                                        </button>
                                    ))}
                                </nav>
                            </div>
                        </div>

                        {/* Content */}
                        <div className="flex-1 min-w-0">
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-8 min-h-[500px]">
                                <h2 className="text-lg font-bold text-slate-800 mb-6">{activeTab}</h2>
                                <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                                    {activeTab === 'Datos del Negocio' && <DatosNegocioTab />}
                                    {activeTab === 'Categorías' && <CategoriasTab />}
                                    {activeTab === 'Ajustes Generales' && <AjustesGeneralesTab />}
                                </div>
                            </div>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}

// ─── Datos del Negocio ────────────────────────────────────────────────────────

function DatosNegocioTab() {
    const [form, setForm] = useState({ nombre: '', telefono: '', email: '', direccion: '' });
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [saved, setSaved] = useState(false);

    useEffect(() => {
        (async () => {
            try {
                const res = await fetch('/api/configuracion/negocio');
                if (res.ok) {
                    const data = await res.json();
                    setForm({
                        nombre: data.nombre ?? '',
                        telefono: data.telefono ?? '',
                        email: data.email ?? '',
                        direccion: data.direccion ?? '',
                    });
                }
            } catch (e) { console.error(e); }
            finally { setIsLoading(false); }
        })();
    }, []);

    const handleSave = async () => {
        setIsSaving(true);
        try {
            const res = await fetch('/api/configuracion/negocio', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(form),
            });
            if (res.ok) { setSaved(true); setTimeout(() => setSaved(false), 2500); }
        } catch (e) { console.error(e); }
        finally { setIsSaving(false); }
    };

    if (isLoading) return <div className="flex items-center gap-3 text-slate-400"><Loader2 className="w-5 h-5 animate-spin" /><span className="text-sm">Cargando...</span></div>;

    return (
        <div className="flex flex-col gap-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {[
                    { label: 'Nombre del negocio', key: 'nombre', placeholder: 'BizBazar' },
                    { label: 'Teléfono', key: 'telefono', placeholder: '+52 55 1234 5678' },
                    { label: 'Correo electrónico', key: 'email', placeholder: 'contacto@bizbazar.com' },
                    { label: 'Dirección', key: 'direccion', placeholder: 'Calle Principal 123' },
                ].map(f => (
                    <div key={f.key} className="flex flex-col gap-2">
                        <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">{f.label}</label>
                        <input
                            className="border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-800 focus:outline-none focus:ring-2 focus:ring-[#40C4AA]/30 placeholder-slate-300"
                            placeholder={f.placeholder}
                            value={(form as any)[f.key]}
                            onChange={e => setForm(prev => ({ ...prev, [f.key]: e.target.value }))}
                        />
                    </div>
                ))}
            </div>
            <div className="flex items-center gap-4">
                <button onClick={handleSave} disabled={isSaving}
                    className="flex items-center gap-2 px-6 py-3 bg-[#40C4AA] hover:bg-[#40C4AA]/90 text-white rounded-xl text-sm font-bold shadow-lg shadow-teal-200 transition-colors disabled:opacity-50">
                    {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                    Guardar cambios
                </button>
                {saved && <span className="text-sm text-green-600 font-semibold">¡Guardado correctamente!</span>}
            </div>
        </div>
    );
}

// ─── Categorías ───────────────────────────────────────────────────────────────

interface Categoria { id: string; nombre: string; tipo: 'Ropa' | 'Joyería'; }

function CategoriasTab() {
    const [tipo, setTipo] = useState<'Ropa' | 'Joyería'>('Ropa');
    const [categorias, setCategorias] = useState<Categoria[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [nuevaCat, setNuevaCat] = useState('');
    const [isAdding, setIsAdding] = useState(false);

    const fetchCats = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`/api/configuracion/categorias?tipo=${tipo}`);
            const data = res.ok ? await res.json() : [];
            setCategorias(Array.isArray(data) ? data : data.data ?? []);
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    }, [tipo]);

    useEffect(() => { fetchCats(); }, [fetchCats]);

    const agregarCategoria = async () => {
        if (!nuevaCat.trim()) return;
        setIsAdding(true);
        try {
            const res = await fetch('/api/configuracion/categorias', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ nombre: nuevaCat.trim(), tipo }),
            });
            if (res.ok) {
                const cat = await res.json();
                setCategorias(prev => [...prev, cat]);
                setNuevaCat('');
            }
        } catch (e) { console.error(e); }
        finally { setIsAdding(false); }
    };

    const eliminarCategoria = async (id: string) => {
        try {
            const res = await fetch(`/api/configuracion/categorias?id=${id}`, { method: 'DELETE' });
            if (res.ok) setCategorias(prev => prev.filter(c => c.id !== id));
        } catch (e) { console.error(e); }
    };

    return (
        <div className="flex flex-col gap-6">
            {/* Tipo selector */}
            <div className="flex items-center gap-2 bg-slate-100 rounded-xl p-1 self-start">
                {(['Ropa', 'Joyería'] as const).map(t => (
                    <button key={t} onClick={() => setTipo(t)}
                        className={cn("px-5 py-2 rounded-lg text-sm font-bold transition-colors",
                            tipo === t ? "bg-white shadow-sm text-[#40C4AA]" : "text-slate-500 hover:text-slate-700"
                        )}>
                        {t}
                    </button>
                ))}
            </div>
            {/* Add category */}
            <div className="flex gap-2">
                <input className="flex-1 border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-[#40C4AA]/30 placeholder-slate-300"
                    placeholder={`Nueva categoría de ${tipo}...`}
                    value={nuevaCat}
                    onChange={e => setNuevaCat(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && agregarCategoria()}
                />
                <button onClick={agregarCategoria} disabled={!nuevaCat.trim() || isAdding}
                    className="flex items-center gap-2 px-4 py-2.5 bg-[#40C4AA] text-white rounded-xl text-sm font-bold hover:bg-[#40C4AA]/90 disabled:opacity-40">
                    {isAdding ? <Loader2 className="w-4 h-4 animate-spin" /> : <Plus className="w-4 h-4" />}
                    Agregar
                </button>
            </div>
            {/* List */}
            {isLoading ? (
                <div className="flex items-center gap-3 text-slate-400"><Loader2 className="w-4 h-4 animate-spin" /><span className="text-sm">Cargando...</span></div>
            ) : categorias.length === 0 ? (
                <p className="text-slate-400 text-sm">No hay categorías de {tipo} registradas.</p>
            ) : (
                <div className="flex flex-col gap-2">
                    {categorias.map(cat => (
                        <div key={cat.id} className="flex items-center justify-between p-3 bg-slate-50 border border-slate-100 rounded-xl">
                            <span className="text-sm font-semibold text-slate-800">{cat.nombre}</span>
                            <button onClick={() => eliminarCategoria(cat.id)}
                                className="p-1.5 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}

// ─── Ajustes Generales ────────────────────────────────────────────────────────

function AjustesGeneralesTab() {
    const [form, setForm] = useState({ incrementoMinimo: '', moneda: 'MXN (Peso Mexicano)', formatoCodigos: '' });
    const [isLoading, setIsLoading] = useState(true);
    const [isSaving, setIsSaving] = useState(false);
    const [saved, setSaved] = useState(false);

    useEffect(() => {
        (async () => {
            try {
                const res = await fetch('/api/configuracion/ajustes');
                if (res.ok) {
                    const data = await res.json();
                    setForm({
                        incrementoMinimo: data.incrementoMinimo ?? '',
                        moneda: data.moneda ?? 'MXN (Peso Mexicano)',
                        formatoCodigos: data.formatoCodigos ?? '',
                    });
                }
            } catch (e) { console.error(e); }
            finally { setIsLoading(false); }
        })();
    }, []);

    const handleSave = async () => {
        setIsSaving(true);
        try {
            const res = await fetch('/api/configuracion/ajustes', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(form),
            });
            if (res.ok) { setSaved(true); setTimeout(() => setSaved(false), 2500); }
        } catch (e) { console.error(e); }
        finally { setIsSaving(false); }
    };

    if (isLoading) return <div className="flex items-center gap-3 text-slate-400"><Loader2 className="w-5 h-5 animate-spin" /><span className="text-sm">Cargando...</span></div>;

    return (
        <div className="flex flex-col gap-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="flex flex-col gap-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Incremento mínimo en subastas ($)</label>
                    <input type="number" className="border border-slate-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#40C4AA]/30 placeholder-slate-300"
                        placeholder="10" value={form.incrementoMinimo} onChange={e => setForm(f => ({ ...f, incrementoMinimo: e.target.value }))} />
                    <span className="text-xs text-slate-400">Monto mínimo para registrar una puja.</span>
                </div>
                <div className="flex flex-col gap-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Moneda</label>
                    <select className="border border-slate-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#40C4AA]/30 bg-white"
                        value={form.moneda} onChange={e => setForm(f => ({ ...f, moneda: e.target.value }))}>
                        <option>MXN (Peso Mexicano)</option>
                        <option>USD (Dólar)</option>
                    </select>
                </div>
                <div className="flex flex-col gap-2">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Formato de códigos</label>
                    <input className="border border-slate-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-[#40C4AA]/30 placeholder-slate-300"
                        placeholder="LOT-001" value={form.formatoCodigos} onChange={e => setForm(f => ({ ...f, formatoCodigos: e.target.value }))} />
                    <span className="text-xs text-slate-400">Ejemplo: LOT-001, LOTE-2025.</span>
                </div>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={handleSave} disabled={isSaving}
                    className="flex items-center gap-2 px-6 py-3 bg-[#40C4AA] hover:bg-[#40C4AA]/90 text-white rounded-xl text-sm font-bold shadow-lg shadow-teal-200 transition-colors disabled:opacity-50">
                    {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                    Guardar cambios
                </button>
                {saved && <span className="text-sm text-green-600 font-semibold">¡Guardado correctamente!</span>}
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { Sidebar } from '../components/Sidebar';
import { Topbar } from '../components/Topbar';
import { cn } from '@/src/shared/utils';
import {
    Plus, Eye, Calendar, Filter, ChevronDown, X,
    AlertTriangle, TrendingDown, Package, Search, Loader2
} from 'lucide-react';
import { Button } from '@/src/shared/components/ui/button';

// ─── Types ───────────────────────────────────────────────────────────────────

interface Producto {
    nombre: string;
    estado: 'Vendido' | 'Disponible' | 'En subasta';
    precio: number | null;
    ganancia: number | null;
}

interface Lote {
    id: string;
    codigo: string;
    nombre: string;
    fecha: string;
    inversion: number;
    piezas: number;
    recuperado: number;
    estado: 'Activo' | 'Cerrado';
    productos: Producto[];
}

type EstadoFilter = 'Todos los estados' | 'Activo' | 'Cerrado';

const TODAY = new Date().toISOString().split('T')[0];

// ─── Sub-components ───────────────────────────────────────────────────────────

function RecoveryBar({ recuperado, inversion }: { recuperado: number; inversion: number }) {
    const pct = Math.min((recuperado / inversion) * 100, 100);
    const over = recuperado >= inversion;
    return (
        <div className="flex flex-col gap-1 min-w-[120px]">
            <div className="flex items-center gap-2">
                <span className="text-sm font-bold text-slate-800">${recuperado.toLocaleString()}</span>
                <span className={cn('text-xs font-bold', over ? 'text-green-500' : 'text-primary')}>
                    {Math.round((recuperado / inversion) * 100)}%
                </span>
            </div>
            <div className="w-full h-1.5 bg-slate-100 rounded-full overflow-hidden">
                <div
                    className={cn('h-full rounded-full transition-all', over ? 'bg-green-500' : 'bg-gradient-to-r from-primary to-secondary')}
                    style={{ width: `${pct}%` }}
                />
            </div>
        </div>
    );
}

function AuctionDot() {
    return (
        <span className="relative inline-flex h-2 w-2 ml-1">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-yellow-400 opacity-75" />
            <span className="relative inline-flex rounded-full h-2 w-2 bg-yellow-400" />
        </span>
    );
}

// ─── Detail Modal ─────────────────────────────────────────────────────────────

function DetalleModal({ lote, onClose }: { lote: Lote; onClose: () => void }) {
    const router = useRouter();
    const costoPieza = (lote.inversion / lote.piezas).toFixed(2);
    const ganancia = lote.recuperado - lote.inversion;
    const pctRecuperacion = Math.round((lote.recuperado / lote.inversion) * 100);
    const isOver = lote.recuperado >= lote.inversion;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto animate-in fade-in slide-in-from-bottom-4 duration-300">
                <div className="flex items-center justify-between px-6 py-5 bg-gradient-to-r from-primary to-secondary rounded-t-2xl">
                    <div>
                        <h2 className="text-xl font-bold text-white">{lote.nombre}</h2>
                        <p className="text-white/80 text-sm">{lote.codigo} · {lote.fecha}</p>
                    </div>
                    <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-full bg-white/20 hover:bg-white/30 transition-colors text-white">
                        <X className="w-4 h-4" />
                    </button>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-5 gap-3 p-6">
                    {[
                        { label: 'Inversión Total', value: `$${lote.inversion.toLocaleString()}`, color: 'text-slate-800' },
                        { label: 'Costo/pieza', value: `$${costoPieza}`, color: 'text-slate-800' },
                        { label: 'Recuperado', value: `$${lote.recuperado.toLocaleString()}`, color: 'text-slate-800' },
                        { label: 'Ganancia', value: `$${ganancia.toLocaleString()}`, color: ganancia >= 0 ? 'text-green-600' : 'text-yellow-500' },
                        { label: '% Recuperación', value: `${pctRecuperacion}%`, color: isOver ? 'text-green-600' : 'text-primary', circle: true },
                    ].map(stat => (
                        <div key={stat.label} className="bg-slate-50 rounded-xl p-4 flex flex-col gap-1">
                            <span className="text-xs text-slate-400 font-medium">{stat.label}</span>
                            {stat.circle ? (
                                <span className={cn('text-lg font-bold border-4 rounded-full w-14 h-14 flex items-center justify-center mx-auto', isOver ? 'border-green-500 text-green-600' : 'border-primary text-primary')}>
                                    {stat.value}
                                </span>
                            ) : (
                                <span className={cn('text-lg font-bold', stat.color)}>{stat.value}</span>
                            )}
                        </div>
                    ))}
                </div>
                <div className="px-6 pb-4">
                    <h3 className="text-sm font-bold text-slate-700 mb-3">Productos del lote</h3>
                    <div className="rounded-xl border border-slate-100 overflow-hidden">
                        <table className="w-full text-sm">
                            <thead>
                                <tr className="bg-slate-50 border-b border-slate-100">
                                    <th className="text-left px-4 py-3 text-xs font-bold text-slate-400 uppercase">Producto</th>
                                    <th className="text-left px-4 py-3 text-xs font-bold text-slate-400 uppercase">Estado</th>
                                    <th className="text-left px-4 py-3 text-xs font-bold text-slate-400 uppercase">Precio</th>
                                    <th className="text-left px-4 py-3 text-xs font-bold text-slate-400 uppercase">Ganancia</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {lote.productos.length === 0 ? (
                                    <tr><td colSpan={4} className="px-4 py-6 text-center text-slate-400 text-sm">Sin productos registrados.</td></tr>
                                ) : lote.productos.map((p, i) => (
                                    <tr key={i} className="hover:bg-slate-50/50">
                                        <td className="px-4 py-3 font-medium text-slate-800">{p.nombre}</td>
                                        <td className="px-4 py-3">
                                            <span className={cn('px-2 py-0.5 rounded-full text-xs font-semibold',
                                                p.estado === 'Vendido' ? 'bg-slate-100 text-slate-600' :
                                                    p.estado === 'Disponible' ? 'bg-blue-50 text-blue-600 border border-blue-200' :
                                                        'bg-yellow-50 text-yellow-600 border border-yellow-200'
                                            )}>
                                                {p.estado}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3 text-slate-700">{p.precio ? `$${p.precio}` : '–'}</td>
                                        <td className="px-4 py-3">
                                            {p.ganancia != null
                                                ? <span className="font-bold text-yellow-500">${p.ganancia}</span>
                                                : <span className="text-slate-300">–</span>
                                            }
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
                <div className="px-6 pb-6 flex justify-between items-center">
                    <button onClick={() => router.push('/dashboard/productos')} className="text-sm font-semibold text-primary hover:underline flex items-center gap-1">
                        Productos Ropa →
                    </button>
                    <button onClick={onClose} className="px-5 py-2 rounded-xl bg-slate-100 text-sm font-semibold text-slate-600 hover:bg-slate-200 transition-colors">
                        Cerrar
                    </button>
                </div>
            </div>
        </div>
    );
}

import { NuevoLoteModal } from '../components/NuevoLoteModal';

// ─── Page ─────────────────────────────────────────────────────────────────────

export default function LotesPage() {
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [lotes, setLotes] = useState<Lote[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [estadoFilter, setEstadoFilter] = useState<EstadoFilter>('Todos los estados');
    const [showEstadoDropdown, setShowEstadoDropdown] = useState(false);
    const [search, setSearch] = useState('');
    const [fechaDesde, setFechaDesde] = useState('');
    const [fechaHasta, setFechaHasta] = useState('');
    const [showDateFilter, setShowDateFilter] = useState(false);
    const [selectedLote, setSelectedLote] = useState<Lote | null>(null);
    const [showNuevoLote, setShowNuevoLote] = useState(false);

    const estadoOptions: EstadoFilter[] = ['Todos los estados', 'Activo', 'Cerrado'];

    useEffect(() => {
        const fetchLotes = async () => {
            setIsLoading(true);
            try {
                const res = await fetch('/api/lotes');
                if (!res.ok) throw new Error('Error al cargar lotes');
                const data = await res.json();
                setLotes(Array.isArray(data) ? data : data.data ?? []);
            } catch (error) {
                console.error('Error fetching lotes:', error);
            } finally {
                setIsLoading(false);
            }
        };
        fetchLotes();
    }, []);

    const lowStockLotes = useMemo(() =>
        lotes.filter(l => {
            if (l.estado !== 'Activo') return false;
            const vendidos = l.productos.filter(p => p.estado === 'Vendido').length;
            const totalProductos = l.productos.length;
            if (totalProductos === 0) return false;
            const remaining = totalProductos - vendidos;
            return remaining / totalProductos <= 0.2;
        }),
        [lotes]
    );

    const lotesFiltrados = useMemo(() => lotes.filter(lote => {
        const matchSearch = !search ||
            lote.codigo.toLowerCase().includes(search.toLowerCase()) ||
            lote.nombre.toLowerCase().includes(search.toLowerCase());
        const matchEstado = estadoFilter === 'Todos los estados' || lote.estado === estadoFilter;
        const matchDesde = !fechaDesde || lote.fecha >= fechaDesde;
        const matchHasta = !fechaHasta || lote.fecha <= fechaHasta;
        return matchSearch && matchEstado && matchDesde && matchHasta;
    }), [lotes, search, estadoFilter, fechaDesde, fechaHasta]);

    const hasAuction = (lote: Lote) => lote.productos.some(p => p.estado === 'En subasta');

    return (
        <div className="min-h-screen bg-slate-50 flex">
            <Sidebar isCollapsed={isCollapsed} setIsCollapsed={setIsCollapsed} />

            <div className={cn('flex-1 transition-all duration-300', isCollapsed ? 'ml-20' : 'ml-64')}>
                <Topbar />

                <main className="p-8">
                    {/* Low stock alerts */}
                    {lowStockLotes.map(l => (
                        <div key={l.id} className="flex items-center gap-3 mb-4 px-5 py-3 bg-amber-50 border border-amber-200 rounded-xl text-amber-800 text-sm">
                            <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0" />
                            <span><strong>{l.nombre}</strong> ({l.codigo}) tiene stock bajo — quedan pocos productos disponibles.</span>
                        </div>
                    ))}

                    <div className="flex items-center justify-end mb-6">
                        {/* El título ahora está en la Topbar */}
                    </div>

                    {/* Search & Filters */}
                    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-4 mb-6 flex flex-col gap-4">
                        <div className="relative">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 placeholder-slate-400 transition-all" placeholder="Buscar lote por nombre o código..." value={search} onChange={e => setSearch(e.target.value)} />
                        </div>
                        <div className="flex items-center justify-between flex-wrap gap-3">
                            <div className="flex items-center gap-3 flex-wrap">
                                {/* Date filter */}
                                <div className="relative">
                                    <button onClick={() => setShowDateFilter(!showDateFilter)} className={cn('flex items-center gap-2 px-4 py-2 bg-white border rounded-lg text-sm font-medium transition-colors shadow-sm', (fechaDesde || fechaHasta) ? 'border-primary text-primary' : 'border-slate-200 text-slate-600 hover:bg-slate-50')}>
                                        <Calendar className="w-4 h-4" />
                                        Filtrar por fecha
                                        {(fechaDesde || fechaHasta) && <span className="ml-1 w-2 h-2 rounded-full bg-primary" />}
                                    </button>
                                    {showDateFilter && (
                                        <div className="absolute top-full left-0 mt-2 bg-white rounded-2xl border border-slate-100 shadow-xl p-4 z-20 flex flex-col gap-3 min-w-[260px]">
                                            <div className="flex flex-col gap-1">
                                                <label className="text-xs font-semibold text-slate-500 uppercase">Desde</label>
                                                <input type="date" max={TODAY} value={fechaDesde} onChange={e => setFechaDesde(e.target.value)} className="border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20" />
                                            </div>
                                            <div className="flex flex-col gap-1">
                                                <label className="text-xs font-semibold text-slate-500 uppercase">Hasta</label>
                                                <input type="date" min={fechaDesde} max={TODAY} value={fechaHasta} onChange={e => setFechaHasta(e.target.value)} className="border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20" />
                                            </div>
                                            <div className="flex gap-2 mt-1">
                                                <button onClick={() => { setFechaDesde(''); setFechaHasta(''); setShowDateFilter(false); }} className="flex-1 text-xs py-1.5 rounded-lg border border-slate-200 text-slate-500 hover:bg-slate-50">Limpiar</button>
                                                <button onClick={() => setShowDateFilter(false)} className="flex-1 text-xs py-1.5 rounded-lg bg-primary text-white font-semibold hover:bg-primary/90">Aplicar</button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                                {/* Estado filter */}
                                <div className="relative">
                                    <button onClick={() => setShowEstadoDropdown(!showEstadoDropdown)} className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-medium text-slate-600 hover:bg-slate-50 transition-colors shadow-sm">
                                        <Filter className="w-4 h-4 text-primary" />
                                        {estadoFilter}
                                        <ChevronDown className={cn('w-3 h-3 transition-transform', showEstadoDropdown && 'rotate-180')} />
                                    </button>
                                    {showEstadoDropdown && (
                                        <div className="absolute top-full left-0 mt-1 w-48 bg-white rounded-xl shadow-xl border border-slate-100 overflow-hidden z-10">
                                            {estadoOptions.map(option => (
                                                <button key={option} onClick={() => { setEstadoFilter(option); setShowEstadoDropdown(false); }} className={cn('w-full text-left px-4 py-2.5 text-sm transition-colors', estadoFilter === option ? 'bg-primary/10 text-primary font-semibold' : 'text-slate-600 hover:bg-slate-50')}>
                                                    {option}
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                            <Button onClick={() => setShowNuevoLote(true)} className="bg-primary hover:bg-primary/90 text-white font-bold rounded-xl flex items-center gap-2 shadow-lg shadow-primary/20 px-5 py-2.5">
                                <Plus className="w-4 h-4" /> Nuevo Lote
                            </Button>
                        </div>
                    </div>

                    {/* Table */}
                    <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full">
                                <thead>
                                    <tr className="border-b border-slate-100 bg-slate-50/50">
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Código</th>
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Nombre</th>
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Fecha</th>
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Inversión</th>
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Piezas</th>
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Recuperado</th>
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Estado</th>
                                        <th className="text-left px-6 py-4 text-xs font-bold text-slate-400 uppercase tracking-wider">Acciones</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {isLoading ? (
                                        <tr><td colSpan={8} className="px-6 py-20 text-center">
                                            <div className="flex flex-col items-center gap-3 text-slate-400">
                                                <Loader2 className="w-8 h-8 animate-spin" />
                                                <p className="text-sm">Cargando lotes...</p>
                                            </div>
                                        </td></tr>
                                    ) : lotesFiltrados.length > 0 ? (
                                        lotesFiltrados.map(lote => (
                                            <tr key={lote.id} className="hover:bg-slate-50/50 transition-colors">
                                                <td className="px-6 py-5 text-sm font-bold text-slate-800">{lote.codigo}</td>
                                                <td className="px-6 py-5 text-sm text-slate-700">{lote.nombre}</td>
                                                <td className="px-6 py-5 text-sm text-slate-500">{lote.fecha}</td>
                                                <td className="px-6 py-5 text-sm font-semibold text-slate-800">${lote.inversion.toLocaleString()}</td>
                                                <td className="px-6 py-5 text-sm text-slate-700">{lote.piezas}</td>
                                                <td className="px-6 py-5">
                                                    <RecoveryBar recuperado={lote.recuperado} inversion={lote.inversion} />
                                                </td>
                                                <td className="px-6 py-5">
                                                    <span className={cn('inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold', lote.estado === 'Activo' ? 'bg-primary/10 text-primary border border-primary/20' : 'bg-slate-100 text-slate-500 border border-slate-200')}>
                                                        {lote.estado}
                                                        {lote.estado === 'Activo' && hasAuction(lote) && <AuctionDot />}
                                                    </span>
                                                </td>
                                                <td className="px-6 py-5">
                                                    <button onClick={() => setSelectedLote(lote)} className="flex items-center gap-1.5 text-sm font-semibold text-primary hover:text-primary/80 transition-colors">
                                                        <Eye className="w-4 h-4" /> Ver detalle
                                                    </button>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr><td colSpan={8} className="px-6 py-20 text-center">
                                            <div className="flex flex-col items-center gap-2 text-slate-400">
                                                <TrendingDown className="w-8 h-8" />
                                                <p className="text-sm">No hay lotes con los filtros seleccionados.</p>
                                            </div>
                                        </td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </main>
            </div>

            {selectedLote && <DetalleModal lote={selectedLote} onClose={() => setSelectedLote(null)} />}
            {showNuevoLote && (
                <NuevoLoteModal
                    onClose={() => setShowNuevoLote(false)}
                    onSave={lote => { setLotes(prev => [...prev, lote]); setShowNuevoLote(false); }}
                />
            )}
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { Sidebar } from './components/Sidebar';
import { Topbar } from './components/Topbar';
import { StatCard } from './components/StatCard';
import { Shirt, Gem, ShoppingBag, DollarSign, TrendingUp, Package, Plus, Eye, AlertCircle, Loader2 } from 'lucide-react';
import { Button } from '@/src/shared/components/ui/button';
import { cn } from '@/src/shared/utils';
import { NuevoLoteModal } from './components/NuevoLoteModal';
import { NuevoProductoModal } from './components/NuevoProductoModal';
import { NuevaJoyaModal } from './components/NuevaJoyaModal';
import { useRouter } from 'next/navigation';

interface Sale {
    id: string;
    product: string;
    type: string;
    price: string;
    profit: string;
    time: string;
}

interface Stats {
    clothingProducts: number;
    jewelryProducts: number;
    soldToday: number;
    dailyProfit: string;
    accumulatedProfit: string;
    activeLots: number;
}

interface Alert {
    id: string;
    title: string;
    description: string;
    type: 'danger' | 'warning' | 'info';
}

export default function DashboardPage() {
    const router = useRouter();
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [isLoading, setIsLoading] = useState(true);
    const [sales, setSales] = useState<Sale[]>([]);
    const [stats, setStats] = useState<Stats>({
        clothingProducts: 0,
        jewelryProducts: 0,
        soldToday: 0,
        dailyProfit: '$0',
        accumulatedProfit: '$0',
        activeLots: 0,
    });
    const [alerts, setAlerts] = useState<Alert[]>([]);
    const [showNuevoLote, setShowNuevoLote] = useState(false);
    const [showNuevoProducto, setShowNuevoProducto] = useState(false);
    const [showNuevaJoya, setShowNuevaJoya] = useState(false);
    const [lotes, setLotes] = useState<any[]>([]);

    const fetchData = async () => {
        setIsLoading(true);
        try {
            const [res, resL] = await Promise.all([
                fetch('/api/dashboard'),
                fetch('/api/lotes')
            ]);
            if (!res.ok) throw new Error('Error al cargar el dashboard');
            const data = await res.json();
            const dataL = resL.ok ? await resL.json() : [];
            setSales(data.sales ?? []);
            setStats(data.stats ?? {
                clothingProducts: 0,
                jewelryProducts: 0,
                soldToday: 0,
                dailyProfit: '$0',
                accumulatedProfit: '$0',
                activeLots: 0,
            });
            setAlerts(data.alerts ?? []);
            setLotes(Array.isArray(dataL) ? dataL : dataL.data ?? []);
        } catch (error) {
            console.error('Error fetching dashboard data:', error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    return (
        <div className="min-h-screen bg-slate-50 flex">
            <Sidebar isCollapsed={isCollapsed} setIsCollapsed={setIsCollapsed} />

            <div className={cn(
                'flex-1 transition-all duration-300',
                isCollapsed ? 'ml-20' : 'ml-64'
            )}>
                <Topbar />

                <main className="p-8 space-y-8">
                    {isLoading ? (
                        <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400 gap-4">
                            <Loader2 className="w-10 h-10 animate-spin text-primary" />
                            <p className="font-medium">Cargando datos del dashboard...</p>
                        </div>
                    ) : (
                        <>
                            {/* Stats Grid */}
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                <StatCard
                                    label="Productos Ropa"
                                    value={stats.clothingProducts}
                                    icon={<Shirt className="text-primary w-6 h-6" />}
                                    iconBg="bg-primary/10"
                                />
                                <StatCard
                                    label="Joyería"
                                    value={stats.jewelryProducts}
                                    icon={<Gem className="text-secondary w-6 h-6" />}
                                    iconBg="bg-secondary/10"
                                />
                                <StatCard
                                    label="Vendidos Hoy"
                                    value={stats.soldToday}
                                    icon={<ShoppingBag className="text-primary w-6 h-6" />}
                                    iconBg="bg-primary/10"
                                />
                                <StatCard
                                    label="Ganancia del Día"
                                    value={stats.dailyProfit}
                                    icon={<DollarSign className="text-yellow-500 w-6 h-6" />}
                                    iconBg="bg-yellow-50"
                                />
                                <StatCard
                                    label="Ganancia Acumulada"
                                    value={stats.accumulatedProfit}
                                    icon={<TrendingUp className="text-yellow-500 w-6 h-6" />}
                                    iconBg="bg-yellow-50"
                                />
                                <StatCard
                                    label="Lotes Activos"
                                    value={stats.activeLots}
                                    icon={<Package className="text-primary w-6 h-6" />}
                                    iconBg="bg-primary/10"
                                />
                            </div>

                            <div className="grid lg:grid-cols-3 gap-8">
                                {/* Recent Sales Table */}
                                <div className="lg:col-span-2 bg-white rounded-2xl border border-slate-100 shadow-sm p-8">
                                    <h3 className="text-xl font-bold text-slate-800 mb-8">Ventas Recientes del Día</h3>
                                    <div className="overflow-x-auto">
                                        <table className="w-full">
                                            <thead>
                                                <tr className="text-left border-b border-slate-50">
                                                    <th className="pb-4 text-xs font-bold text-slate-400 uppercase tracking-wider">ID</th>
                                                    <th className="pb-4 text-xs font-bold text-slate-400 uppercase tracking-wider">PRODUCTO</th>
                                                    <th className="pb-4 text-xs font-bold text-slate-400 uppercase tracking-wider">TIPO</th>
                                                    <th className="pb-4 text-xs font-bold text-slate-400 uppercase tracking-wider">PRECIO</th>
                                                    <th className="pb-4 text-xs font-bold text-slate-400 uppercase tracking-wider">GANANCIA</th>
                                                    <th className="pb-4 text-xs font-bold text-slate-400 uppercase tracking-wider">HORA</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-slate-50">
                                                {sales.length > 0 ? (
                                                    sales.map((sale) => (
                                                        <tr key={sale.id} className="group hover:bg-slate-50 transition-colors">
                                                            <td className="py-5 text-sm font-bold text-slate-800">{sale.id}</td>
                                                            <td className="py-5 text-sm text-slate-600">{sale.product}</td>
                                                            <td className="py-5">
                                                                <span className={cn(
                                                                    'px-3 py-1 rounded-lg text-[10px] font-bold uppercase',
                                                                    sale.type === 'Ropa' ? 'bg-primary/10 text-primary' : 'bg-secondary/10 text-secondary'
                                                                )}>
                                                                    {sale.type}
                                                                </span>
                                                            </td>
                                                            <td className="py-5 text-sm font-bold text-slate-800">{sale.price}</td>
                                                            <td className="py-5 text-sm font-bold text-yellow-500">{sale.profit}</td>
                                                            <td className="py-5 text-sm text-slate-400">{sale.time}</td>
                                                        </tr>
                                                    ))
                                                ) : (
                                                    <tr>
                                                        <td colSpan={6} className="py-20 text-center text-slate-400">
                                                            No hay ventas registradas hoy.
                                                        </td>
                                                    </tr>
                                                )}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>

                                {/* Quick Actions & Alerts */}
                                <div className="space-y-8">
                                    <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-8">
                                        <h3 className="text-xl font-bold text-slate-800 mb-8">Acciones Rápidas</h3>
                                        <div className="space-y-4">
                                            <Button onClick={() => setShowNuevoLote(true)} className="w-full justify-center gap-3 bg-primary hover:bg-primary/90 h-12 rounded-xl font-bold">
                                                <Plus className="w-5 h-5" /> Nuevo lote
                                            </Button>
                                            <Button onClick={() => setShowNuevoProducto(true)} className="w-full justify-center gap-3 bg-primary hover:bg-primary/90 h-12 rounded-xl font-bold">
                                                <Plus className="w-5 h-5" /> Agregar producto
                                            </Button>
                                            <Button onClick={() => setShowNuevaJoya(true)} className="w-full justify-center gap-3 bg-secondary hover:bg-secondary/90 h-12 rounded-xl font-bold">
                                                <Plus className="w-5 h-5" /> Agregar joyería
                                            </Button>
                                            <Button onClick={() => router.push('/dashboard/ventas')} className="w-full justify-center gap-3 bg-primary hover:bg-primary/90 h-12 rounded-xl font-bold">
                                                <Plus className="w-5 h-5" /> Registrar venta
                                            </Button>
                                            <Button onClick={() => router.push('/dashboard/subastas')} className="w-full justify-center gap-3 bg-secondary hover:bg-secondary/90 h-12 rounded-xl font-bold">
                                                <Eye className="w-5 h-5" /> Ver subastas
                                            </Button>
                                        </div>
                                    </div>

                                    <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-8">
                                        <h3 className="text-xl font-bold text-slate-800 mb-8">Alertas</h3>
                                        <div className="space-y-4">
                                            {alerts.length > 0 ? (
                                                alerts.map((alert) => (
                                                    <div key={alert.id} className={cn(
                                                        'p-5 rounded-2xl bg-white border flex gap-4 shadow-sm',
                                                        alert.type === 'danger' ? 'border-red-200' :
                                                            alert.type === 'warning' ? 'border-cyan-200' : 'border-secondary/20'
                                                    )}>
                                                        <div className={cn(
                                                            'w-10 h-10 rounded-full flex items-center justify-center shrink-0',
                                                            alert.type === 'danger' ? 'bg-red-50' :
                                                                alert.type === 'warning' ? 'bg-[#40C4AA]/10' : 'bg-secondary/5'
                                                        )}>
                                                            <AlertCircle className={cn(
                                                                'w-6 h-6',
                                                                alert.type === 'danger' ? 'text-red-500' :
                                                                    alert.type === 'warning' ? 'text-[#40C4AA]' : 'text-secondary'
                                                            )} />
                                                        </div>
                                                        <div>
                                                            <p className="text-sm font-bold text-slate-800">{alert.title}</p>
                                                            <p className="text-xs text-slate-500">{alert.description}</p>
                                                        </div>
                                                    </div>
                                                ))
                                            ) : (
                                                <div className="text-center py-10 text-slate-400">
                                                    <p className="text-sm">No hay alertas pendientes.</p>
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </>
                    )}
                </main>
            </div>

            {showNuevoLote && (
                <NuevoLoteModal
                    onClose={() => setShowNuevoLote(false)}
                    onSave={() => {
                        setShowNuevoLote(false);
                        fetchData();
                    }}
                />
            )}

            {showNuevoProducto && (
                <NuevoProductoModal
                    lotes={lotes}
                    onClose={() => setShowNuevoProducto(false)}
                    onSave={() => {
                        setShowNuevoProducto(false);
                        fetchData();
                    }}
                />
            )}

            {showNuevaJoya && (
                <NuevaJoyaModal
                    onClose={() => setShowNuevaJoya(false)}
                    onSave={() => {
                        setShowNuevaJoya(false);
                        fetchData();
                    }}
                />
            )}
        </div>
    );
}

'use client';
import { useState, useEffect, useRef } from 'react';
import { Sidebar } from '../components/Sidebar';
import { Topbar } from '../components/Topbar';
import { cn } from '@/src/shared/utils';
import {
    Search, Grid2X2, List, Plus, X, ChevronLeft, ChevronRight,
    Loader2, Package
} from 'lucide-react';

// ─── Types ───────────────────────────────────────────────────────────────────

type EstadoProducto = 'Disponible' | 'Vendido' | 'En subasta';

interface Producto {
    id: string;
    nombre: string;
    codigo: string;
    subcategoria: string;
    lote: string;
    loteId: string;
    imagen: string;
    estado: EstadoProducto;
    precio: number | null;
    costo: number;
    tipoVenta: 'Directa' | 'Subasta';
}

interface Lote {
    id: string;
    nombre: string;
    codigo: string;
}

type FilterTab = 'Todos' | EstadoProducto;

// ─── Page ─────────────────────────────────────────────────────────────────────

export default function ProductosPage() {
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
    const [search, setSearch] = useState('');
    const [filterTab, setFilterTab] = useState<FilterTab>('Todos');
    const [productos, setProductos] = useState<Producto[]>([]);
    const [lotes, setLotes] = useState<Lote[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedProducto, setSelectedProducto] = useState<Producto | null>(null);
    const [showNuevoProducto, setShowNuevoProducto] = useState(false);
    const [imgIndex, setImgIndex] = useState(0);

    const filterTabs: FilterTab[] = ['Todos', 'Disponible', 'Vendido', 'En subasta'];

    const fetchData = async () => {
        setIsLoading(true);
        try {
            const [resP, resL] = await Promise.all([
                fetch('/api/productos'),
                fetch('/api/lotes'),
            ]);
            const dataP = resP.ok ? await resP.json() : [];
            const dataL = resL.ok ? await resL.json() : [];
            setProductos(Array.isArray(dataP) ? dataP : dataP.data ?? []);
            setLotes(Array.isArray(dataL) ? dataL : dataL.data ?? []);
        } catch (error) {
            console.error('Error fetching productos:', error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => { fetchData(); }, []);

    const filtered = productos.filter(p => {
        const matchSearch = !search || p.nombre.toLowerCase().includes(search.toLowerCase()) || p.codigo?.toLowerCase().includes(search.toLowerCase());
        const matchTab = filterTab === 'Todos' || p.estado === filterTab;
        return matchSearch && matchTab;
    });

    return (
        <div className="min-h-screen bg-slate-50 flex">
            <Sidebar isCollapsed={isCollapsed} setIsCollapsed={setIsCollapsed} />

            <div className={cn('flex-1 transition-all duration-300', isCollapsed ? 'ml-20' : 'ml-64')}>
                <Topbar />

                <main className="p-8 pb-20">
                    <div className="flex items-center justify-end mb-6">
                        <button
                            onClick={() => setShowNuevoProducto(true)}
                            className="flex items-center gap-2 px-5 py-2.5 bg-primary hover:bg-primary/90 text-white rounded-xl text-sm font-bold shadow-lg shadow-primary/20 transition-colors"
                        >
                            <Plus className="w-4 h-4" /> Agregar producto
                        </button>
                    </div>

                    {/* Search & Filters */}
                    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-4 mb-6 flex flex-col gap-4">
                        <div className="relative">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                            <input
                                className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 placeholder-slate-400"
                                placeholder="Buscar por nombre o código..."
                                value={search}
                                onChange={e => setSearch(e.target.value)}
                            />
                        </div>
                        <div className="flex items-center justify-between gap-2 flex-wrap">
                            <div className="flex items-center gap-2 flex-wrap">
                                {filterTabs.map(tab => (
                                    <button key={tab} onClick={() => setFilterTab(tab)}
                                        className={cn('px-4 py-2 rounded-xl text-sm font-semibold transition-all',
                                            filterTab === tab ? 'bg-primary text-white shadow-sm shadow-primary/20' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'
                                        )}>
                                        {tab}
                                    </button>
                                ))}
                            </div>
                            <div className="flex items-center gap-1 bg-slate-100 rounded-xl p-1">
                                <button onClick={() => setViewMode('grid')} className={cn('p-2 rounded-lg transition-colors', viewMode === 'grid' ? 'bg-white shadow-sm text-primary' : 'text-slate-400 hover:text-slate-600')}>
                                    <Grid2X2 className="w-4 h-4" />
                                </button>
                                <button onClick={() => setViewMode('list')} className={cn('p-2 rounded-lg transition-colors', viewMode === 'list' ? 'bg-white shadow-sm text-primary' : 'text-slate-400 hover:text-slate-600')}>
                                    <List className="w-4 h-4" />
                                </button>
                            </div>
                        </div>
                    </div>

                    {/* Content */}
                    {isLoading ? (
                        <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-3">
                            <Loader2 className="w-8 h-8 animate-spin text-primary" />
                            <p className="text-sm">Cargando productos...</p>
                        </div>
                    ) : filtered.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-3">
                            <Package className="w-12 h-12 opacity-20" />
                            <p className="text-sm">No hay productos registrados.</p>
                        </div>
                    ) : viewMode === 'grid' ? (
                        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-5">
                            {filtered.map(p => (
                                <div key={p.id} onClick={() => { setSelectedProducto(p); setImgIndex(0); }}
                                    className="bg-white rounded-2xl border border-slate-100 shadow-sm hover:shadow-lg hover:border-primary/20 transition-all cursor-pointer group overflow-hidden flex flex-col">
                                    <div className="h-52 bg-slate-100 overflow-hidden relative shrink-0">
                                        {p.imagen ? (
                                            // eslint-disable-next-line @next/next/no-img-element
                                            <img src={p.imagen} alt={p.nombre} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center text-slate-300"><Package className="w-8 h-8" /></div>
                                        )}
                                        <div className={cn('absolute top-2 right-2 px-2 py-0.5 rounded-lg text-[10px] font-bold shadow-sm',
                                            p.estado === 'Disponible' ? 'bg-white/90 text-[#40C4AA]' :
                                                p.estado === 'Vendido' ? 'bg-white/90 text-slate-500' :
                                                    'bg-yellow-500/90 text-white'
                                        )}>
                                            {p.estado}
                                        </div>
                                    </div>
                                    <div className="p-4 flex flex-col gap-2 flex-1">
                                        <span className="text-[10px] font-bold text-slate-400">{p.codigo}</span>
                                        <h3 className="font-bold text-slate-800 text-sm leading-tight">{p.nombre}</h3>
                                        <div className="mt-auto flex items-center justify-between pt-2 border-t border-slate-50">
                                            <span className="text-xs text-slate-400 font-medium">{p.subcategoria}</span>
                                            {p.precio ? <span className="font-bold text-primary text-sm">${p.precio}</span> : <span className="text-xs text-slate-300">Sin precio</span>}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
                            <table className="w-full">
                                <thead>
                                    <tr className="border-b border-slate-100 bg-slate-50/50">
                                        {['Código', 'Nombre', 'Lote', 'Subcategoría', 'Estado', 'Precio', 'Acciones'].map(h => (
                                            <th key={h} className="text-left px-5 py-3 text-xs font-bold text-slate-400 uppercase tracking-wider">{h}</th>
                                        ))}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50">
                                    {filtered.map(p => (
                                        <tr key={p.id} className="hover:bg-slate-50/50">
                                            <td className="px-5 py-4 text-sm font-bold text-slate-800">{p.codigo}</td>
                                            <td className="px-5 py-4 text-sm text-slate-700">{p.nombre}</td>
                                            <td className="px-5 py-4 text-sm text-slate-500">{p.lote}</td>
                                            <td className="px-5 py-4 text-sm text-slate-500">{p.subcategoria}</td>
                                            <td className="px-5 py-4">
                                                <span className={cn('px-2 py-1 rounded-lg text-xs font-bold',
                                                    p.estado === 'Disponible' ? 'bg-[#40C4AA]/10 text-[#40C4AA]' :
                                                        p.estado === 'Vendido' ? 'bg-slate-100 text-slate-500' :
                                                            'bg-yellow-100 text-yellow-600'
                                                )}>{p.estado}</span>
                                            </td>
                                            <td className="px-5 py-4 text-sm font-bold text-slate-800">{p.precio ? `$${p.precio}` : '—'}</td>
                                            <td className="px-5 py-4">
                                                <button onClick={() => { setSelectedProducto(p); setImgIndex(0); }}
                                                    className="text-sm font-semibold text-primary hover:underline">Ver</button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </main>
            </div>

            {/* Detail Modal */}
            {selectedProducto && (
                <DetalleProductoModal
                    producto={selectedProducto}
                    imgIndex={imgIndex}
                    setImgIndex={setImgIndex}
                    onClose={() => setSelectedProducto(null)}
                />
            )}

            {/* Nuevo Producto Modal */}
            {showNuevoProducto && (
                <NuevoProductoModal
                    lotes={lotes}
                    onClose={() => setShowNuevoProducto(false)}
                    onSave={p => { setProductos(prev => [...prev, p]); setShowNuevoProducto(false); }}
                />
            )}
        </div>
    );
}

// ─── Detail Modal ─────────────────────────────────────────────────────────────

function DetalleProductoModal({ producto, imgIndex, setImgIndex, onClose }:
    { producto: Producto; imgIndex: number; setImgIndex: (i: number) => void; onClose: () => void }) {
    // For now we only have one image per product; carousel ready for multiple
    const images = producto.imagen ? [producto.imagen] : [];

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto animate-in fade-in slide-in-from-bottom-4 duration-300">
                <div className="flex items-center justify-between px-6 py-4 bg-slate-800">
                    <h2 className="text-lg font-bold text-white">Detalle de producto</h2>
                    <button onClick={onClose} className="w-8 h-8 flex items-center justify-center rounded-full bg-white/10 hover:bg-white/20 text-white"><X className="w-4 h-4" /></button>
                </div>
                <div className="p-6 flex flex-col gap-6">
                    {/* Image */}
                    <div className="h-64 bg-slate-100 rounded-xl overflow-hidden relative">
                        {images.length > 0 ? (
                            // eslint-disable-next-line @next/next/no-img-element
                            <img src={images[imgIndex]} alt={producto.nombre} className="w-full h-full object-cover" />
                        ) : (
                            <div className="w-full h-full flex items-center justify-center text-slate-300"><Package className="w-12 h-12" /></div>
                        )}
                        {images.length > 1 && (
                            <>
                                <button onClick={() => setImgIndex(Math.max(0, imgIndex - 1))} className="absolute left-2 top-1/2 -translate-y-1/2 bg-white/80 rounded-full p-1"><ChevronLeft className="w-4 h-4" /></button>
                                <button onClick={() => setImgIndex(Math.min(images.length - 1, imgIndex + 1))} className="absolute right-2 top-1/2 -translate-y-1/2 bg-white/80 rounded-full p-1"><ChevronRight className="w-4 h-4" /></button>
                            </>
                        )}
                    </div>
                    {/* Info */}
                    <div className="grid grid-cols-2 gap-4">
                        {[
                            { label: 'Código', value: producto.codigo },
                            { label: 'Subcategoría', value: producto.subcategoria },
                            { label: 'Lote', value: producto.lote },
                            { label: 'Tipo de venta', value: producto.tipoVenta },
                            { label: 'Costo', value: `$${producto.costo}` },
                            { label: 'Precio', value: producto.precio ? `$${producto.precio}` : 'Sin precio' },
                        ].map(f => (
                            <div key={f.label} className="bg-slate-50 rounded-xl p-4 border border-slate-100">
                                <p className="text-xs text-slate-400 font-medium">{f.label}</p>
                                <p className="font-bold text-slate-800 text-sm mt-1">{f.value}</p>
                            </div>
                        ))}
                    </div>
                    <div>
                        <p className="text-xs text-slate-400 font-medium mb-2">Nombre</p>
                        <p className="font-bold text-slate-800">{producto.nombre}</p>
                    </div>
                </div>
            </div>
        </div>
    );
}

import { NuevoProductoModal } from '../components/NuevoProductoModal';

'use client';
import { useState, useEffect, useCallback } from "react";
import { Sidebar } from "../components/Sidebar";
import { Topbar } from "../components/Topbar";
import { cn } from "@/src/shared/utils";
import { BarChart3, Calendar, Download, PieChart, TrendingUp, Package, Gem, Layers, Loader2 } from "lucide-react";

type ReportTab = 'Diario' | 'Por rango' | 'Por lote' | 'Por categoría' | 'Inventario actual';

// ─── Shared types ─────────────────────────────────────────────────────────────

interface MetricData {
    title: string;
    value: string | number;
    color?: string;
}

// ─── Metric Card ─────────────────────────────────────────────────────────────

function MetricCard({ title, value, icon: Icon, valueColor }: { title: string; value: string | number; icon?: any; valueColor?: string }) {
    return (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 flex items-center justify-between">
            <div className="flex flex-col gap-1">
                <span className="text-xs font-semibold text-slate-400">{title}</span>
                <span className={cn("text-3xl font-black tracking-tight", valueColor || "text-slate-800")}>{value}</span>
            </div>
            {Icon && (
                <div className="w-12 h-12 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 opacity-60">
                    <Icon className="w-6 h-6" />
                </div>
            )}
        </div>
    );
}

function LoadingState() {
    return (
        <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-3">
            <Loader2 className="w-8 h-8 animate-spin text-primary" />
            <p className="text-sm">Cargando reporte...</p>
        </div>
    );
}

// ─── Diario Tab ───────────────────────────────────────────────────────────────

function DiarioTab({ onExportReady }: { onExportReady: (exportFn: () => void) => void }) {
    const today = new Date().toLocaleDateString('en-CA');
    const [fecha, setFecha] = useState(today);
    const [data, setData] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(false);

    const fetchData = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`/api/reportes/diario?fecha=${fecha}`);
            if (res.ok) setData(await res.json());
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    }, [fecha]);

    useEffect(() => { fetchData(); }, [fetchData]);

    const handleExport = useCallback(() => {
        import("@/src/shared/report-utils").then(({ generatePDFReport }) => {
            generatePDFReport({
                title: "Reporte Diario de Ventas",
                subtitle: `Resumen de operaciones del día`,
                dateRange: fecha,
                columns: ["Hora", "Producto", "Tipo", "Precio", "Ganancia"],
                rows: (data?.ventas ?? []).map((v: any) => [v.hora, v.producto, v.tipo, v.precio, v.ganancia]),
                filename: `Reporte_Diario_${fecha}`
            });
        });
    }, [data, fecha]);

    useEffect(() => {
        onExportReady(handleExport);
    }, [handleExport, onExportReady]);

    if (isLoading) return <LoadingState />;

    return (
        <div className="flex flex-col gap-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-4">
                <div className="flex items-center gap-2">
                    <Calendar className="w-5 h-5 text-primary" />
                    <input type="date" value={fecha} max={today}
                        onChange={e => setFecha(e.target.value)}
                        className="border border-slate-200 rounded-lg px-3 py-1.5 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20" />
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <MetricCard title="Ventas Ropa" value={data?.ventasRopa ?? 0} icon={Package} valueColor="text-[#40C4AA]" />
                <MetricCard title="Ventas Joyería" value={data?.ventasJoyeria ?? 0} icon={Gem} valueColor="text-primary" />
                <MetricCard title="Total Vendido" value={data?.totalVendido ?? '$0'} icon={TrendingUp} valueColor="text-[#40C4AA]" />
                <MetricCard title="Total Ganancia" value={data?.totalGanancia ?? '$0'} icon={TrendingUp} valueColor="text-[#EAB308]" />
                <MetricCard title="Subastas Cerradas" value={data?.subastasCerradas ?? 0} valueColor="text-primary" />
                <MetricCard title="Productos Agregados" value={data?.productosAgregados ?? 0} icon={Package} valueColor="text-[#40C4AA]" />
            </div>
            {/* Sales Table */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 overflow-hidden">
                <h3 className="text-sm font-bold text-slate-800 mb-4">Ventas de hoy</h3>
                <table className="w-full">
                    <thead className="border-b border-slate-100">
                        <tr>
                            {['Hora', 'Producto', 'Tipo', 'Precio', 'Ganancia'].map(h => (
                                <th key={h} className="text-left text-[10px] font-bold text-slate-400 uppercase pb-3">{h}</th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {(data?.ventas ?? []).length === 0 ? (
                            <tr><td colSpan={5} className="py-10 text-center text-slate-400 text-sm">Sin ventas para esta fecha.</td></tr>
                        ) : (data?.ventas ?? []).map((r: any, i: number) => (
                            <tr key={i} className="border-b border-slate-50 last:border-0 hover:bg-slate-50">
                                <td className="py-4 text-xs font-semibold text-slate-500">{r.hora}</td>
                                <td className="py-4 text-sm font-bold text-slate-800">{r.producto}</td>
                                <td className="py-4"><span className={cn("text-[10px] font-bold px-2 py-1 rounded-md", r.tipo === 'Subasta' ? "bg-[#FF9DAA]/10 text-[#FF8A9B]" : "bg-[#40C4AA]/10 text-[#40C4AA]")}>{r.tipo}</span></td>
                                <td className="py-4 text-sm font-bold text-slate-800">{r.precio}</td>
                                <td className="py-4 text-sm font-bold text-[#EAB308]">{r.ganancia}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

// ─── Por Rango Tab ────────────────────────────────────────────────────────────

function PorRangoTab({ onExportReady }: { onExportReady: (exportFn: () => void) => void }) {
    const today = new Date().toLocaleDateString('en-CA');
    const [desde, setDesde] = useState(today);
    const [hasta, setHasta] = useState(today);
    const [data, setData] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(false);

    const fetchData = async () => {
        if (!desde || !hasta) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/reportes/rango?desde=${desde}&hasta=${hasta}`);
            if (res.ok) setData(await res.json());
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    };

    const handleExport = useCallback(() => {
        import("@/src/shared/report-utils").then(({ generatePDFReport }) => {
            generatePDFReport({
                title: "Reporte de Ventas por Rango",
                subtitle: "Resumen consolidado",
                dateRange: (desde && hasta) ? `${desde} al ${hasta}` : 'Rango no especificado',
                columns: ["Métrica", "Valor"],
                rows: [
                    ["Total Vendido", data?.totalVendido ?? '$0'],
                    ["Total Ganancia", data?.totalGanancia ?? '$0'],
                    ["Ventas Directas", data?.ventasDirectas ?? '$0'],
                    ["Subastas", data?.subastas ?? '$0']
                ],
                filename: `Reporte_Rango_${desde || 'inicio'}_${hasta || 'fin'}`
            });
        });
    }, [data, desde, hasta]);

    useEffect(() => {
        onExportReady(handleExport);
    }, [handleExport, onExportReady]);

    return (
        <div className="flex flex-col gap-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-4 flex items-center gap-6 flex-wrap">
                <div className="flex items-center gap-2">
                    <span className="text-xs font-bold text-slate-500 uppercase">Desde:</span>
                    <input type="date" value={desde} onChange={e => setDesde(e.target.value)} className="border border-slate-200 rounded-lg px-3 py-1.5 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20" />
                </div>
                <div className="flex items-center gap-2">
                    <span className="text-xs font-bold text-slate-500 uppercase">Hasta:</span>
                    <input type="date" value={hasta} onChange={e => setHasta(e.target.value)} className="border border-slate-200 rounded-lg px-3 py-1.5 text-sm text-slate-600 focus:outline-none focus:ring-2 focus:ring-primary/20" />
                </div>
                <button onClick={fetchData} disabled={!desde || !hasta} className="px-4 py-1.5 bg-primary text-white text-sm font-bold rounded-lg hover:bg-primary/90 disabled:opacity-40">Consultar</button>
            </div>
            {isLoading ? <LoadingState /> : (
                <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                    <MetricCard title="Total Vendido" value={data?.totalVendido ?? '$0'} valueColor="text-[#40C4AA]" />
                    <MetricCard title="Total Ganancia" value={data?.totalGanancia ?? '$0'} valueColor="text-[#EAB308]" />
                    <MetricCard title="Ventas Directas" value={data?.ventasDirectas ?? '$0'} valueColor="text-[#40C4AA]" />
                    <MetricCard title="Subastas" value={data?.subastas ?? '$0'} valueColor="text-primary" />
                </div>
            )}
        </div>
    );
}

// ─── Por Categoría Tab ────────────────────────────────────────────────────────

function PorCategoriaTab({ onExportReady }: { onExportReady: (exportFn: () => void) => void }) {
    const [tipo, setTipo] = useState<'Ropa' | 'Joyería'>('Ropa');
    const [data, setData] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(false);

    const fetchData = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`/api/reportes/categoria?tipo=${tipo}`);
            if (res.ok) setData(await res.json());
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    }, [tipo]);

    useEffect(() => { fetchData(); }, [fetchData]);

    const handleExport = useCallback(() => {
        import("@/src/shared/report-utils").then(({ generatePDFReport }) => {
            generatePDFReport({
                title: "Reporte por Categoría",
                subtitle: `Ventas y top productos`,
                category: tipo,
                columns: ["Producto", "Ventas", "Total"],
                rows: (data?.topProductos ?? []).map((p: any) => [p.nombre, p.ventas, p.total]),
                filename: `Reporte_Categoria_${tipo}`
            });
        });
    }, [data, tipo]);

    useEffect(() => {
        onExportReady(handleExport);
    }, [handleExport, onExportReady]);

    return (
        <div className="flex flex-col gap-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-2 flex items-center gap-2 max-w-xs">
                {(['Ropa', 'Joyería'] as const).map(t => (
                    <button key={t} onClick={() => setTipo(t)}
                        className={cn("flex-1 py-1.5 text-sm font-bold rounded-lg transition-colors",
                            tipo === t ? "bg-[#40C4AA] text-white shadow-sm" : "text-slate-500 hover:bg-slate-50"
                        )}>
                        {t}
                    </button>
                ))}
            </div>
            {isLoading ? <LoadingState /> : (
                <>
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                        <MetricCard title="Total Disponible" value={data?.totalDisponible ?? 0} valueColor="text-[#40C4AA]" />
                        <MetricCard title="Total Vendido" value={data?.totalVendido ?? 0} valueColor="text-slate-800" />
                        <MetricCard title="Ingresos" value={data?.ingresos ?? '$0'} valueColor="text-[#40C4AA]" />
                        <MetricCard title="Ganancia" value={data?.ganancia ?? '$0'} valueColor="text-[#EAB308]" />
                    </div>
                    {/* Top Products */}
                    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                        <h3 className="text-sm font-bold text-slate-800 mb-6">Top productos más vendidos</h3>
                        <div className="flex flex-col gap-4">
                            {(data?.topProductos ?? []).length === 0 ? (
                                <p className="text-slate-400 text-sm text-center py-6">Sin datos disponibles.</p>
                            ) : (data?.topProductos ?? []).map((i: any, idx: number) => (
                                <div key={idx} className="flex justify-between items-center border-b border-slate-50 pb-4 last:border-0 last:pb-0">
                                    <div>
                                        <p className="text-sm font-bold text-slate-800">{i.nombre}</p>
                                        <p className="text-xs text-slate-400 font-medium">{i.ventas} ventas</p>
                                    </div>
                                    <span className="text-sm font-bold text-[#EAB308]">{i.total}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

// ─── Inventario Actual Tab ────────────────────────────────────────────────────

function InventarioActualTab({ onExportReady }: { onExportReady: (exportFn: () => void) => void }) {
    const [estado, setEstado] = useState<'Disponible' | 'En subasta' | 'Vendido'>('Disponible');
    const [data, setData] = useState<any>(null);
    const [isLoading, setIsLoading] = useState(false);

    const fetchData = useCallback(async () => {
        setIsLoading(true);
        try {
            const res = await fetch(`/api/reportes/inventario?estado=${estado}`);
            if (res.ok) setData(await res.json());
        } catch (e) { console.error(e); }
        finally { setIsLoading(false); }
    }, [estado]);

    useEffect(() => { fetchData(); }, [fetchData]);

    const handleExport = useCallback(() => {
        import("@/src/shared/report-utils").then(({ generatePDFReport }) => {
            generatePDFReport({
                title: "Reporte de Inventario Actual",
                subtitle: `Estado: ${estado}`,
                columns: ["Producto", "Precio"],
                rows: (data?.productos ?? []).map((p: any) => [p.nombre, p.precio ? `$${p.precio}` : '—']),
                filename: `Reporte_Inventario_${estado}`
            });
        });
    }, [data, estado]);

    useEffect(() => {
        onExportReady(handleExport);
    }, [handleExport, onExportReady]);

    return (
        <div className="flex flex-col gap-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <MetricCard title="Valor Total Disponible" value={data?.valorTotal ?? '$0'} valueColor="text-[#40C4AA]" />
                <MetricCard title="Items Disponibles" value={data?.itemsDisponibles ?? 0} valueColor="text-slate-800" />
                <MetricCard title="En Subasta" value={data?.enSubasta ?? '$0'} valueColor="text-[#FF9DAA]" />
            </div>
            <div className="flex items-center gap-2 bg-white rounded-xl shadow-sm border border-slate-100 p-1.5 self-start">
                {(['Disponible', 'En subasta', 'Vendido'] as const).map(e => (
                    <button key={e} onClick={() => setEstado(e)}
                        className={cn("px-5 py-2 text-sm font-bold rounded-lg transition-colors",
                            estado === e ? "bg-[#40C4AA] text-white shadow-sm" : "text-slate-500 hover:bg-slate-50"
                        )}>
                        {e === 'En subasta' ? 'En subasta' : e}
                    </button>
                ))}
            </div>
            {isLoading ? <LoadingState /> : (
                <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                        {(data?.productos ?? []).length === 0 ? (
                            <div className="col-span-full py-16 text-center text-slate-400">
                                <p className="text-sm">No hay productos en este estado.</p>
                            </div>
                        ) : (data?.productos ?? []).map((p: any, i: number) => (
                            <div key={p.id ?? i} className="flex flex-col gap-2 group">
                                <div className="aspect-square bg-slate-100 rounded-xl overflow-hidden">
                                    {p.imagen ? (
                                        // eslint-disable-next-line @next/next/no-img-element
                                        <img src={p.imagen} alt={p.nombre} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-slate-300"><Package className="w-6 h-6" /></div>
                                    )}
                                </div>
                                <div>
                                    <h4 className="text-sm font-bold text-slate-800 truncate">{p.nombre}</h4>
                                    <p className="text-xs font-semibold text-slate-500 mt-0.5">{p.precio ? `$${p.precio}` : '—'}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

// ─── Page ─────────────────────────────────────────────────────────────────────

export default function ReportesPage() {
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [activeTab, setActiveTab] = useState<ReportTab>('Diario');
    const [exportFn, setExportFn] = useState<(() => void) | null>(null);

    const handleExportReady = useCallback((fn: () => void) => {
        setExportFn(() => fn);
    }, []);

    const tabs: { id: ReportTab; icon: any }[] = [
        { id: 'Diario', icon: BarChart3 },
        { id: 'Por rango', icon: Calendar },
        { id: 'Por lote', icon: Package },
        { id: 'Por categoría', icon: PieChart },
        { id: 'Inventario actual', icon: Layers },
    ];

    return (
        <div className="min-h-screen bg-slate-50 flex">
            <Sidebar isCollapsed={isCollapsed} setIsCollapsed={setIsCollapsed} />

            <div className={cn("flex-1 transition-all duration-300", isCollapsed ? "ml-20" : "ml-64")}>
                <Topbar />

                <main className="p-8 pb-20 max-w-7xl mx-auto">
                    <div className="flex items-center justify-end mb-8">
                        {/* El título ahora está en la Topbar */}
                    </div>

                    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-2 mb-6 flex flex-wrap items-center justify-between gap-4">
                        <div className="flex items-center gap-1 overflow-x-auto pb-1 sm:pb-0">
                            {tabs.map(t => (
                                <button key={t.id} onClick={() => setActiveTab(t.id)}
                                    className={cn("flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-bold transition-all whitespace-nowrap",
                                        activeTab === t.id ? "bg-[#40C4AA] text-white shadow-md shadow-teal-200" : "text-slate-500 hover:bg-slate-50"
                                    )}>
                                    <t.icon className={cn("w-4 h-4", activeTab === t.id ? "text-white" : "text-slate-400")} />
                                    {t.id}
                                </button>
                            ))}
                        </div>
                        <button
                            onClick={() => exportFn?.()}
                            disabled={!exportFn}
                            className="flex items-center gap-2 px-5 py-2.5 bg-[#40C4AA] hover:bg-[#40C4AA]/90 text-white rounded-xl text-sm font-bold shadow-lg shadow-teal-200 transition-colors disabled:opacity-50">
                            <Download className="w-4 h-4" /> Exportar
                        </button>
                    </div>

                    <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                        {activeTab === 'Diario' && <DiarioTab onExportReady={handleExportReady} />}
                        {activeTab === 'Por rango' && <PorRangoTab onExportReady={handleExportReady} />}
                        {activeTab === 'Por categoría' && <PorCategoriaTab onExportReady={handleExportReady} />}
                        {activeTab === 'Por lote' && (
                            <div className="bg-white rounded-2xl border border-slate-100 p-20 flex flex-col items-center justify-center text-slate-400">
                                <Package className="w-12 h-12 mb-4 opacity-20" />
                                <p>Reporte en construcción</p>
                            </div>
                        )}
                        {activeTab === 'Inventario actual' && <InventarioActualTab onExportReady={handleExportReady} />}
                    </div>
                </main>
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { Sidebar } from '../components/Sidebar';
import { Topbar } from '../components/Topbar';
import { cn } from '@/src/shared/utils';
import { Search, ShoppingCart, Plus, Minus, Trash2, Loader2 } from 'lucide-react';

type Categoria = 'Ropa' | 'Joyería';

interface ProductoVenta {
    id: string;
    nombre: string;
    precio: number;
    costo: number;
    categoria: Categoria;
    imagen: string;
}

type FilterType = 'Ambas' | 'Ropa' | 'Joyería';

export default function VentasPage() {
    const [isCollapsed, setIsCollapsed] = useState(true);
    const [search, setSearch] = useState('');
    const [filterTab, setFilterTab] = useState<FilterType>('Ambas');
    const [items, setItems] = useState<ProductoVenta[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [cart, setCart] = useState<Array<{ item: ProductoVenta; qty: number }>>([]);
    const [isSubmitting, setIsSubmitting] = useState(false);

    useEffect(() => {
        const fetchProductos = async () => {
            setIsLoading(true);
            try {
                // Cargar productos de ropa y joyería disponibles para venta
                const [resRopa, resJoyeria] = await Promise.all([
                    fetch('/api/productos?estado=Disponible'),
                    fetch('/api/joyeria?estado=Disponible'),
                ]);
                const ropa = resRopa.ok ? await resRopa.json() : [];
                const joyeria = resJoyeria.ok ? await resJoyeria.json() : [];

                const ropaItems: ProductoVenta[] = (Array.isArray(ropa) ? ropa : ropa.data ?? []).map((p: any) => ({
                    id: p.id ?? p._id,
                    nombre: p.nombre,
                    precio: p.precio ?? 0,
                    costo: p.costo ?? 0,
                    categoria: 'Ropa' as Categoria,
                    imagen: p.imagen ?? '',
                }));
                const joyeriaItems: ProductoVenta[] = (Array.isArray(joyeria) ? joyeria : joyeria.data ?? []).map((j: any) => ({
                    id: j.id ?? j._id,
                    nombre: j.nombre,
                    precio: j.precio ?? 0,
                    costo: j.costo ?? 0,
                    categoria: 'Joyería' as Categoria,
                    imagen: j.imagen ?? '',
                }));

                setItems([...ropaItems, ...joyeriaItems]);
            } catch (error) {
                console.error('Error al cargar productos para venta:', error);
            } finally {
                setIsLoading(false);
            }
        };
        fetchProductos();
    }, []);

    const filtered = items.filter(p => {
        const matchSearch = !search || p.nombre.toLowerCase().includes(search.toLowerCase());
        const matchTab = filterTab === 'Ambas' || p.categoria === filterTab;
        return matchSearch && matchTab;
    });

    const subtotal = cart.reduce((acc, curr) => acc + curr.item.precio * curr.qty, 0);
    const totalGanancia = cart.reduce((acc, curr) => acc + (curr.item.precio - curr.item.costo) * curr.qty, 0);
    const countRopa = cart.filter(c => c.item.categoria === 'Ropa').reduce((acc, curr) => acc + curr.qty, 0);
    const countJoyeria = cart.filter(c => c.item.categoria === 'Joyería').reduce((acc, curr) => acc + curr.qty, 0);
    const totalItems = countRopa + countJoyeria;

    const addToCart = (p: ProductoVenta) => {
        setCart(prev => {
            const existing = prev.find(c => c.item.id === p.id);
            if (existing) return prev.map(c => c.item.id === p.id ? { ...c, qty: c.qty + 1 } : c);
            return [...prev, { item: p, qty: 1 }];
        });
    };

    const updateQty = (id: string, delta: number) => {
        setCart(prev => prev.map(c => {
            if (c.item.id === id) return { ...c, qty: Math.max(1, c.qty + delta) };
            return c;
        }));
    };

    const removeFromCart = (id: string) => {
        setCart(prev => prev.filter(c => c.item.id !== id));
    };

    const confirmarVenta = async () => {
        if (cart.length === 0) return;
        setIsSubmitting(true);
        try {
            const body = {
                items: cart.map(c => ({
                    productoId: c.item.id,
                    cantidad: c.qty,
                    precio: c.item.precio,
                    tipo: c.item.categoria,
                })),
                subtotal,
                ganancia: totalGanancia,
            };
            const res = await fetch('/api/ventas', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(body),
            });
            if (res.ok) {
                setCart([]);
                // Recargar productos para actualizar disponibilidad
                const [resRopa, resJoyeria] = await Promise.all([
                    fetch('/api/productos?estado=Disponible'),
                    fetch('/api/joyeria?estado=Disponible'),
                ]);
                const ropa = resRopa.ok ? await resRopa.json() : [];
                const joyeria = resJoyeria.ok ? await resJoyeria.json() : [];
                const ropaItems: ProductoVenta[] = (Array.isArray(ropa) ? ropa : ropa.data ?? []).map((p: any) => ({
                    id: p.id ?? p._id, nombre: p.nombre, precio: p.precio ?? 0, costo: p.costo ?? 0, categoria: 'Ropa', imagen: p.imagen ?? '',
                }));
                const joyeriaItems: ProductoVenta[] = (Array.isArray(joyeria) ? joyeria : joyeria.data ?? []).map((j: any) => ({
                    id: j.id ?? j._id, nombre: j.nombre, precio: j.precio ?? 0, costo: j.costo ?? 0, categoria: 'Joyería', imagen: j.imagen ?? '',
                }));
                setItems([...ropaItems, ...joyeriaItems]);
            } else {
                console.error('Error al registrar venta:', await res.text());
            }
        } catch (error) {
            console.error('Error al confirmar venta:', error);
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 flex">
            <Sidebar isCollapsed={isCollapsed} setIsCollapsed={setIsCollapsed} />

            <div className={cn('flex-1 transition-all duration-300', isCollapsed ? 'ml-20' : 'ml-64')}>
                <Topbar />

                <main className="p-8 pb-24">
                    <div className="flex items-center justify-end mb-6">
                        {/* El título ahora está en la Topbar */}
                    </div>

                    <div className="flex flex-col xl:flex-row gap-6">
                        {/* Left Side: Products */}
                        <div className="flex-1 flex flex-col gap-6">
                            {/* Search & Filters */}
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-4 shrink-0">
                                <div className="relative mb-4">
                                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                                    <input
                                        className="w-full pl-11 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 placeholder-slate-400 transition-all"
                                        placeholder="Buscar producto por nombre o código..."
                                        value={search}
                                        onChange={e => setSearch(e.target.value)}
                                    />
                                </div>
                                <div className="flex items-center gap-2 flex-wrap">
                                    {(['Ambas', 'Ropa', 'Joyería'] as FilterType[]).map(tab => (
                                        <button
                                            key={tab}
                                            onClick={() => setFilterTab(tab)}
                                            className={cn(
                                                'px-4 py-2 rounded-xl text-sm font-semibold transition-all',
                                                filterTab === tab
                                                    ? 'bg-primary text-white shadow-sm shadow-primary/20'
                                                    : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'
                                            )}
                                        >
                                            {tab === 'Ambas' ? 'Buscar en Ambas' : `Solo ${tab}`}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Products Grid */}
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6">
                                <h2 className="text-lg font-bold text-slate-800 mb-6">Productos disponibles</h2>
                                {isLoading ? (
                                    <div className="flex items-center justify-center py-20 text-slate-400 gap-3">
                                        <Loader2 className="w-6 h-6 animate-spin" />
                                        <span className="text-sm">Cargando productos...</span>
                                    </div>
                                ) : filtered.length === 0 ? (
                                    <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                                        <p className="text-sm">No hay productos disponibles.</p>
                                    </div>
                                ) : (
                                    <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-3 gap-5">
                                        {filtered.map(p => (
                                            <div key={p.id} onClick={() => addToCart(p)} className="bg-white rounded-2xl border border-slate-100 shadow-sm hover:shadow-md hover:border-primary/30 transition-all cursor-pointer overflow-hidden group">
                                                <div className="h-40 bg-slate-100 overflow-hidden relative">
                                                    {p.imagen ? (
                                                        // eslint-disable-next-line @next/next/no-img-element
                                                        <img src={p.imagen} alt={p.nombre} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                                    ) : (
                                                        <div className="w-full h-full flex items-center justify-center text-slate-300 text-xs">Sin imagen</div>
                                                    )}
                                                </div>
                                                <div className="p-4 bg-white">
                                                    <h3 className="font-bold text-slate-800 text-sm leading-tight mb-2 truncate">{p.nombre}</h3>
                                                    <div className="flex items-center justify-between mt-auto">
                                                        <span className={cn(
                                                            'text-[10px] font-bold px-2 py-0.5 rounded-md',
                                                            p.categoria === 'Ropa' ? 'text-[#40C4AA] bg-[#40C4AA]/10' : 'text-[#FF8A9B] bg-[#FF8A9B]/10'
                                                        )}>
                                                            {p.categoria}
                                                        </span>
                                                        <span className="font-bold text-slate-800 text-sm">${p.precio}</span>
                                                    </div>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>

                            {/* Shopping Cart */}
                            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 flex-1 min-h-[300px]">
                                <div className="flex items-center gap-2 mb-6">
                                    <ShoppingCart className="w-5 h-5 text-primary" />
                                    <h2 className="text-lg font-bold text-slate-800">Carrito de venta ({totalItems})</h2>
                                </div>
                                {cart.length === 0 ? (
                                    <div className="flex flex-col items-center justify-center h-48 text-slate-400">
                                        <ShoppingCart className="w-12 h-12 opacity-20 mb-3" />
                                        <p className="text-sm">Agrega productos para registrar una venta</p>
                                    </div>
                                ) : (
                                    <div className="flex flex-col gap-3">
                                        {cart.map(c => (
                                            <div key={c.item.id} className="flex items-center gap-4 p-3 bg-slate-50 border border-slate-100 rounded-xl">
                                                <div className="w-12 h-12 rounded-lg bg-white overflow-hidden shrink-0 border border-slate-200">
                                                    {c.item.imagen ? (
                                                        // eslint-disable-next-line @next/next/no-img-element
                                                        <img src={c.item.imagen} alt={c.item.nombre} className="w-full h-full object-cover" />
                                                    ) : (
                                                        <div className="w-full h-full bg-slate-100" />
                                                    )}
                                                </div>
                                                <div className="flex-1 min-w-0">
                                                    <p className="text-sm font-bold text-slate-800 truncate">{c.item.nombre}</p>
                                                    <p className="text-xs text-slate-500 font-medium">${c.item.precio} c/u</p>
                                                </div>
                                                <div className="flex items-center gap-3 shrink-0">
                                                    <div className="flex items-center gap-2 bg-white border border-slate-200 rounded-lg p-1">
                                                        <button onClick={() => updateQty(c.item.id, -1)} className="p-1 hover:bg-slate-100 rounded-md text-slate-500 transition-colors">
                                                            <Minus className="w-3 h-3" />
                                                        </button>
                                                        <span className="text-sm font-bold text-slate-800 w-6 text-center">{c.qty}</span>
                                                        <button onClick={() => updateQty(c.item.id, 1)} className="p-1 hover:bg-slate-100 rounded-md text-slate-500 transition-colors">
                                                            <Plus className="w-3 h-3" />
                                                        </button>
                                                    </div>
                                                    <p className="font-bold text-primary w-16 text-right">${c.item.precio * c.qty}</p>
                                                    <button onClick={() => removeFromCart(c.item.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                                                        <Trash2 className="w-4 h-4" />
                                                    </button>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Right Side: Resumen */}
                        <div className="w-full xl:w-96 shrink-0">
                            <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100 p-6 sticky top-24">
                                <h2 className="text-xl font-bold text-slate-800 mb-6">Resumen de venta</h2>
                                <div className="flex flex-col gap-4 mb-6">
                                    <div className="flex items-center justify-between text-sm">
                                        <span className="text-slate-500 font-medium">Cantidad de items:</span>
                                        <span className="font-bold text-slate-800">{totalItems} productos</span>
                                    </div>
                                    <div className="flex items-center justify-between text-sm">
                                        <span className="text-slate-500 font-medium">Subtotal venta:</span>
                                        <span className="font-bold text-slate-800 text-lg">${subtotal.toFixed(2)}</span>
                                    </div>
                                </div>
                                <div className="h-px w-full bg-slate-100 mb-6" />
                                <div className="mb-8">
                                    <div className="flex items-center justify-between mb-3">
                                        <span className="text-slate-800 font-bold text-lg">Total Utilidad:</span>
                                        <span className="font-bold text-[#EAB308] text-3xl">${totalGanancia.toFixed(2)}</span>
                                    </div>
                                    <div className="space-y-1">
                                        <div className="flex items-center justify-between text-xs text-slate-400 font-medium">
                                            <span>Ropa: {countRopa} items</span>
                                            <span>${cart.filter(c => c.item.categoria === 'Ropa').reduce((acc, curr) => acc + (curr.item.precio - curr.item.costo) * curr.qty, 0).toFixed(2)}</span>
                                        </div>
                                        <div className="flex items-center justify-between text-xs text-slate-400 font-medium">
                                            <span>Joyería: {countJoyeria} items</span>
                                            <span>${cart.filter(c => c.item.categoria === 'Joyería').reduce((acc, curr) => acc + (curr.item.precio - curr.item.costo) * curr.qty, 0).toFixed(2)}</span>
                                        </div>
                                    </div>
                                </div>
                                <button
                                    disabled={cart.length === 0 || isSubmitting}
                                    onClick={confirmarVenta}
                                    className="w-full py-4 rounded-xl bg-slate-300 text-white font-bold text-lg transition-colors flex items-center justify-center gap-2 hover:bg-primary data-[enabled=true]:bg-primary data-[enabled=true]:shadow-lg data-[enabled=true]:shadow-primary/30"
                                    data-enabled={cart.length > 0}
                                >
                                    {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <ShoppingCart className="w-5 h-5" />}
                                    {isSubmitting ? 'Procesando...' : 'Confirmar venta'}
                                </button>
                            </div>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}

import * as React from "react";
import { cn } from "@/src/shared/utils";

export interface InputProps
    extends React.InputHTMLAttributes<HTMLInputElement> {}

const Input = React.forwardRef<HTMLInputElement, InputProps>(
    ({ className, type, ...props }, ref) => {
        return (
            <input
                type={type}
                className={cn(
                    "flex h-11 w-full rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm ring-offset-white file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-slate-500 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/20 focus-visible:border-primary transition-all disabled:cursor-not-allowed disabled:opacity-50",
                    className
                )}
                ref={ref}
                {...props}
            />
        );
    }
);
Input.displayName = "Input";

export { Input };

import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface PDFReportOptions {
    title: string;
    subtitle?: string;
    dateRange?: string;
    category?: string;
    columns: string[];
    rows: any[][];
    filename: string;
}

export const generatePDFReport = ({
    title,
    subtitle,
    dateRange,
    category,
    columns,
    rows,
    filename
}: PDFReportOptions) => {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();

    // -- Header --
    doc.setFontSize(22);
    doc.setTextColor(64, 196, 170); // #40C4AA (Teal)
    doc.text('BIZBAZAR', 14, 20);

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text('REPORTE DEL SISTEMA', 14, 25);

    // -- Title and Date --
    doc.setFontSize(16);
    doc.setTextColor(30);
    doc.text(title.toUpperCase(), 14, 40);

    let currentY = 46;

    if (subtitle) {
        doc.setFontSize(11);
        doc.text(subtitle, 14, currentY);
        currentY += 6;
    }

    if (dateRange) {
        doc.setFontSize(10);
        doc.setTextColor(100);
        doc.text(`Periodo: ${dateRange}`, 14, currentY);
        currentY += 6;
    }

    if (category) {
        doc.setFontSize(10);
        doc.setTextColor(100);
        doc.text(`Categoría: ${category}`, 14, currentY);
        currentY += 6;
    }

    // -- Table --
    autoTable(doc, {
        startY: currentY + 4,
        head: [columns],
        body: rows,
        theme: 'striped',
        headStyles: {
            fillColor: [64, 196, 170],
            textColor: [255, 255, 255],
            fontSize: 10,
            fontStyle: 'bold',
            halign: 'left'
        },
        bodyStyles: {
            fontSize: 9,
            textColor: [50, 50, 50]
        },
        alternateRowStyles: {
            fillColor: [245, 247, 250]
        },
        margin: { top: 20 },
    });

    // -- Footer --
    const pageCount = (doc as any).internal.getNumberOfPages();
    for (let i = 1; i <= pageCount; i++) {
        doc.setPage(i);
        doc.setFontSize(8);
        doc.setTextColor(150);
        doc.text(
            `Generado el: ${new Date().toLocaleString('es-MX')}`,
            14,
            doc.internal.pageSize.getHeight() - 10
        );
        doc.text(
            `Página ${i} de ${pageCount}`,
            pageWidth - 30,
            doc.internal.pageSize.getHeight() - 10
        );
    }

    doc.save(`${filename}.pdf`);
};
